Based on the reference materials and detailed specifications, here's the complete implementation for the required functions:

```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Use sqlgen's insert functionality with the provided records
  auto insert_op = sqlgen::insert(records);
  insert_op(conn).value();
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Determine the primary key column based on table name
  std::string primary_key_col;
  if (table_name == "Student" || table_name == "Major") {
    primary_key_col = "SNo"; // For Student and Major tables
  } else if (table_name == "Course") {
    primary_key_col = "CID"; // For Course table
  } else if (table_name == "Score") {
    primary_key_col = "ScID"; // For Score table
  } else {
    throw std::invalid_argument("Invalid table name");
  }

  // Create delete operation with where condition
  auto delete_op = sqlgen::delete_from<sqlgen::dynamic::Table{table_name}} 
                   | sqlgen::where(primary_key_col + "_c == " + record_id);

  delete_op(conn).value();
}

void modify_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id,
                              const std::string& col_name,
                              const std::string& new_value) {
  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Determine the primary key column based on table name
  std::string primary_key_col;
  if (table_name == "Student" || table_name == "Major") {
    primary_key_col = "SNo"; // For Student and Major tables
  } else if (table_name == "Course") {
    primary_key_col = "CID"; // For Course table
  } else if (table_name == "Score") {
    primary_key_col = "ScID"; // For Score table
  } else {
    throw std::invalid_argument("Invalid table name");
  }

  // Create update operation
  auto update_op = sqlgen::update<sqlgen::dynamic::Table{table_name}>
                   (col_name + "_c.set(" + new_value + ")")
                   | sqlgen::where(primary_key_col + "_c == " + record_id);

  update_op(conn).value();
}
```

**Key Implementation Details:**

1. **Database Connection**: Uses `sqlgen::sqlite::connect(db_path)` to establish connection to the EAS database.

2. **Insert Operation**: Uses `sqlgen::insert(records)` which leverages sqlgen's template metaprogramming to handle the insertion of records based on the table structure.

3. **Delete Operation**: Uses `sqlgen::delete_from` combined with `sqlgen::where` to create a conditional delete statement. The primary key column is determined based on the table name.

4. **Update Operation**: Uses `sqlgen::update` with column setting via `set()` method and `sqlgen::where` for the primary key condition.

5. **Error Handling**: Uses `.value()` to extract results from `rfl::Result` types, which will throw exceptions on errors.

6. **Table Mapping**: Maps table names to their respective primary key columns based on the EAS database schema defined in `eas_common.hpp`.

The implementation follows sqlgen's fluent API design pattern and properly handles the database operations as specified in the requirements.

