    if (!conn_result) {
        return {};
    }
    auto conn = conn_result.value();

    // 2. Create User and Post tables with if_not_exists modifier
    auto create_user = sqlgen::create_table<User> | sqlgen::if_not_exists;
    auto create_post = sqlgen::create_table<Post> | sqlgen::if_not_exists;

    // Execute table creation
    if (auto result = create_user(conn); !result) {
