std::vector<PurchaseHistory> query_customer_purchase_history(int customer_id) {
  using namespace sqlgen::literals;

  // 1. Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // 2. Create tables using sqlgen::create_table with if_not_exists modifier
  conn | sqlgen::create_table<Customer> | sqlgen::if_not_exists;
  conn | sqlgen::create_table<Order> | sqlgen::if_not_exists;
  conn | sqlgen::create_table<OrderItem> | sqlgen::if_not_exists;
  conn | sqlgen::create_table<Product> | sqlgen::if_not_exists;

