  auto result = sqlgen::select_from<Customer, "c">(
      "name"_t1.as<"product_name">,
      "order_date"_t2,
      "quantity"_t3
    )
    | sqlgen::inner_join<Order, "o">("customer_id"_t1 == "customer_id"_t2)
    | sqlgen::inner_join<OrderItem, "oi">("order_id"_t2 == "order_id"_t3)
    | sqlgen::inner_join<Product, "p">("product_id"_t3 == "product_id"_t4)
    | sqlgen::where("customer_id"_t1 == customer_id)
    | sqlgen::order_by("order_date"_t2.desc())
