 * This function demonstrates how to use upsert (insert or replace) statements in sqlgen write API.
 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false; // Connection failed
  }

  auto conn = conn_result.value();

  // Perform upsert operation with or_replace=true
  auto write_result = sqlgen::write(conn, items, true);
  if (!write_result) {
    return false; // Write operation failed
  }

  // Verify upsert behavior by reading back the items
  auto read_result = sqlgen::read<std::vector<Inventory>>(conn);
  if (!read_result) {
    return false; // Read operation failed
  }

  auto retrieved_items = read_result.value();

  // Verify that the number of items matches and the data is consistent
  if (items.size() != retrieved_items.size()) {
    return false; // Size mismatch
  }

  // Verify each item's data
  for (size_t i = 0; i < items.size(); ++i) {
    if (items[i].item_id != retrieved_items[i].item_id ||
        items[i].name != retrieved_items[i].name ||
        items[i].quantity != retrieved_items[i].quantity) {
      return false; // Data mismatch found
    }
  }

  return true; // All operations succeeded and data matches
}

}  // namespace upsert_inventory_items
