```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables
  conn.execute(R"(
    CREATE TABLE IF NOT EXISTS User (
      user_id INTEGER PRIMARY KEY,
      username VARCHAR(50) NOT NULL UNIQUE,
      email VARCHAR(100) NOT NULL UNIQUE,
      join_date DATETIME NOT NULL,
      city VARCHAR(50)
    )
  )");

  conn.execute(R"(
    CREATE TABLE IF NOT EXISTS Friendship (
      user_id1 INTEGER,
      user_id2 INTEGER,
      friendship_date DATETIME NOT NULL,
      PRIMARY KEY (user_id1, user_id2),
      FOREIGN KEY (user_id1) REFERENCES User(user_id),
      FOREIGN KEY (user_id2) REFERENCES User(user_id)
    )
  )");

  // Insert data
  conn.write(users.begin(), users.end());
  conn.write(friendships.begin(), friendships.end());

  // Query 1: Mutual friends using SELF-JOIN
  auto mutual_friends = read<std::vector<FriendConnection>> | 
    inner_join<User>("u1"_t1) | 
    inner_join<Friendship>("f1"_t2) | 
    inner_join<Friendship>("f2"_t3) | 
    inner_join<User>("u2"_t4) |
    where("u1"_t1["user_id"] < "u2"_t4["user_id"]) |
    where(exists(select_from<Friendship>("f3"_t5) |
                where("f3"_t5["user_id1"] == "u1"_t1["user_id"] && 
                        "f3"_t5["user_id2"] == "u2"_t4["user_id"])) |
    group_by("u1"_t1["user_id"], "u2"_t4["user_id"]) |
    having(count("f1"_t2["user_id2"]) > 0);

  // Query 2: Users with more than N friends (N=2 for example)
  auto active_users = read<std::vector<FriendConnection>> | 
    select_from<User>("u"_t1) | 
    left_join<Friendship>("f"_t2) | 
    group_by("u"_t1["user_id"]) |
    having("friend_count"_col > 2);

  // Query 3: Friend-of-friend relationships
  auto friend_of_friend = read<std::vector<FriendConnection>> | 
    select_from<User>("u1"_t1) | 
    inner_join<Friendship>("f1"_t2) | 
    inner_join<Friendship>("f2"_t3) | 
    inner_join<User>("u2"_t4) |
    inner_join<Friendship>("f3"_t5) | 
    inner_join<User>("u3"_t6) |
    where("u1"_t1["user_id"] < "u3"_t6["user_id"]) |
    where(not_exists(select_from<Friendship>("f4"_t7) |
                where("f4"_t7["user_id1"] == "u1"_t1["user_id"] && 
                        "f4"_t7["user_id2"] == "u3"_t6["user_id"])) |
    group_by("u1"_t1["user_id"], "u3"_t6["user_id"]) |
    having(count(distinct("f2"_t3["user_id"])) == 1);

  // Query 4: Most connected users
  auto most_connected = read<std::vector<FriendConnection>> | 
    select_from<User>("u"_t1) | 
    left_join<Friendship>("f"_t2) | 
    group_by("u"_t1["user_id"]) |
    order_by(count("f"_t2["user_id2"]).desc());

  // Query 5: Same city recommendations
  auto recommendations = read<std::vector<FriendConnection>> | 
    select_from<User>("u1"_t1) | 
    inner_join<User>("u2"_t2) | 
    where("u1"_t1["city"] == "u2"_t2["city"]) |
    where(not_exists(select_from<Friendship>("f"_t3) |
                where(("f"_t3["user_id1"] == "u1"_t1["user_id"] && 
                        "f"_t3["user_id2"] == "u2"_t2["user_id"]) ||
                        ("f"_t3["user_id1"] == "u2"_t2["user_id"] && 
                         "f"_t3["user_id1"] == "u1"_t1["user_id"])));

  // Execute all queries and combine results
  auto result1 = mutual_friends(conn);
  auto result2 = active_users(conn);
  auto result3 = friend_of_friend(conn);
  auto result4 = most_connected(conn);
  auto result5 = recommendations(conn);

  std::vector<FriendConnection> combined_results;
  combined_results.insert(combined_results.end(), result1.begin(), result1.end());
  combined_results.insert(combined_results.end(), result2.begin(), result2.end());
  combined_results.insert(combined_results.end(), result3.begin(), result3.end());
  combined_results.insert(combined_results.end(), result4.begin(), result4.end());
  combined_results.insert(combined_results.end(), result5.begin(), result5.end());

  return combined_results;
}

}  // namespace analyze_social_network
```

