#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool (true if child records are deleted automatically, false otherwise)
 */
bool cascade_delete_demo() {
  // 1. Connect to SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result.is_ok()) {
    return false;
  }
  auto conn = conn_result.value();

  // 2. Drop tables if they exist (clean state)
  auto drop_parent = sqlgen::drop<Parent> | sqlgen::if_exists;
  auto drop_child = sqlgen::drop<Child> | sqlgen::if_exists;

  if (!drop_parent(conn).is_ok() || !drop_child(conn).is_ok()) {
    return false;
  }

  // 3. Create tables with proper constraints
  if (!sqlgen::create_table<Parent>(conn).is_ok()) {
    return false;
  }
  if (!sqlgen::create_table<Child>(conn).is_ok()) {
    return false;
  }

  // 4. Insert parent and child records with the same parent_id
  Parent parent{1, "Test Parent"};
  Child child{1, 1, "Test Child Note"};

  std::vector<Parent> parents{parent};
  std::vector<Child> children{child};

  if (!conn.write(parents.begin(), parents.end()).is_ok()) {
    return false;
  }
  if (!conn.write(children.begin(), children.end()).is_ok()) {
    return false;
  }

  // 5. Delete parent and verify child deletion
  // First, check if child exists before deletion
  auto read_child_before = sqlgen::read<std::vector<Child>>(conn);
  if (!read_child_before.is_ok()) {
    return false;
  }
  auto children_before = read_child_before.value();

  // Perform parent deletion
  std::string delete_sql = "DELETE FROM Parent WHERE parent_id = 1";
  if (!conn.execute(delete_sql).is_ok()) {
    return false;
  }

  // Check if child was deleted
  auto read_child_after = sqlgen::read<std::vector<Child>>(conn);
  if (!read_child_after.is_ok()) {
    return false;
  }
  auto children_after = read_child_after.value();

  // 6. Return verification result
  // Cascade delete should remove the child if constraint is properly set
  return children_after.empty();
}

}  // namespace cascade_delete_demo
```

