  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables if they don't exist
  conn.execute(R"(
    CREATE TABLE IF NOT EXISTS Department (
      department_id INTEGER PRIMARY KEY,
      department_name TEXT NOT NULL,
      location TEXT
    )
  )");

  conn.execute(R"(
    CREATE TABLE IF NOT EXISTS Employee (
      employee_id INTEGER PRIMARY KEY,
      department_id INTEGER,
      first_name TEXT NOT NULL,
      last_name TEXT NOT NULL,
      salary REAL NOT NULL,
      FOREIGN KEY (department_id) REFERENCES Department(department_id)
    )
  )");

  // Insert department data
  for (const auto& dept : depts) {
    conn.execute(R"(
      INSERT INTO Department (department_id, department_name, location)
      VALUES ("")").replace("", std::to_string(dept.department_id))
                   .replace("", dept.department_name)
                   .replace("", dept.location) + ")";
  }

  // Insert employee data
  for (const auto& emp : emps) {
    conn.execute(R"(
      INSERT INTO Employee (employee_id, department_id, first_name, last_name, salary)
      VALUES ("")").replace("", std::to_string(emp.employee_id))
                   .replace("", std::to_string(emp.department_id))
                   .replace("", emp.first_name)
                   .replace("", emp.last_name)
                   .replace("", std::to_string(emp.salary)) + ")";
  }

  // Perform INNER JOIN
  auto inner_query = sqlgen::select_from<Department>("department_name"_c, "first_name"_c, "last_name"_c, "salary"_c)
                   | sqlgen::inner_join<Employee>("department_id"_c == "department_id"_c);

  auto inner_results = conn.read<std::vector<JoinResult>>(inner_query);

  // Perform LEFT JOIN
  auto left_query = sqlgen::select_from<Employee>("department_name"_c, "first_name"_c, "last_name"_c, "salary"_c)
                   | sqlgen::left_join<Department>("department_id"_c == "department_id"_c);

  auto left_results = conn.read<std::vector<JoinResult>>(left_query);

  // Perform RIGHT JOIN
  auto right_query = sqlgen::select_from<Employee>("department_name"_c, "first_name"_c, "last_name"_c, "salary"_c)
                   | sqlgen::right_join<Department>("department_id"_c == "department_id"_c);

  auto right_results = conn.read<std::vector<JoinResult>>(right_query);

  // Perform FULL JOIN
  auto full_query = sqlgen::select_from<Department>("department_name"_c, "first_name"_c, "last_name"_c, "salary"_c)
                   | sqlgen::full_join<Employee>("department_id"_c == "department_id"_c);

  auto full_results = conn.read<std::vector<JoinResult>>(full_query);

  return JoinAnalysis{
      .inner_join_results = inner_results.value(),
      .left_join_results = left_results.value(),
      .right_join_results = right_results.value(),
      .full_join_results = full_results.value()
  };
}

}  // namespace analyze_department_employees
```

**Key Implementation Details:**

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to "test_db.sqlite"

2. **Table Creation**: Creates Department and Employee tables with proper schema matching the reference structures

3. **Data Insertion**: Inserts the provided department and employee data using parameterized SQL execution

4. **Join Operations**:
   - **INNER JOIN**: Uses `sqlgen::select_from` with `sqlgen::inner_join` to get employees with assigned departments
   - **LEFT JOIN**: Uses `sqlgen::select_from` with `sqlgen::left_join` to include all employees (even without departments)
   - **RIGHT JOIN**: Uses `sqlgen::select_from` with `sqlgen::right_join` to include all departments (even without employees)
   - **FULL JOIN**: Uses `sqlgen::select_from` with `sqlgen::full_join` to include all employees and departments

5. **Result Collection**: Executes each query and collects results into `std::vector<JoinResult>` containers

6. **Return Value**: Returns a `JoinAnalysis` object containing all four join results

The implementation follows sqlgen best practices by using the fluent API for query construction and properly handling the optional nature of join results through `std::optional` fields in the `JoinResult` structure.

